-- Seed privacy policy markdown content in ops_settings
INSERT INTO public.ops_settings (key, value)
VALUES (
  'privacy_policy_markdown',
  E'# Privacy Policy\n\nEffective: January 26, 2025\n\nThis Privacy Policy governs the use of the Didi Now mobile app and web platform available at https://user.didisnow.com operated by Didi Now Private Limited, Prestige High Fields, Hyderabad – 500032.\n\nThis Policy is published in compliance with the Information Technology Act, 2000 and the Information Technology (Reasonable security practices and procedures and sensitive personal data or information) Rules, 2011.\n\nBy using our Platform or Services, you agree to the collection, storage, processing, and transfer of your information as described below. If you do not agree, please do not use the Platform.\n\n## 1. Information We Collect\n\n- Personal details: name, address, phone number, email, UPI ID, and other contact data.\n- Residential details: family size, flat size/rooms, presence of pets, etc.\n- Usage data: logins, bookings, interactions with the app.\n- Device & access info: IP address, browser/OS.\n- Location data: if you grant permission.\n\n## 2. How We Use Your Information\n\n- Provide and improve services\n- Match you with available service experts (maids, cooks)\n- Process payments and issue invoices\n- Send alerts, notifications, confirmations\n- Resolve support requests\n- Comply with legal obligations\n- Internal analytics and performance evaluation\n\n## 3. Sharing of Information\n\nWe do not sell or rent your data. We may share it with:\n\n- Experts to fulfill your bookings\n- Service providers (hosting, support, payments)\n- Legal authorities when required by law\n- Others only with your explicit consent\n\n## 4. Cookies & Tracking\n\nWe may use cookies or similar technologies to enhance experience and analyze performance. You can control cookies in your browser settings.\n\n## 5. Data Retention\n\nWe retain data while your account is active or as needed for the purposes above. You may request deletion by emailing team@didisnow.com.\n\n## 6. Data Security\n\nWe implement commercially reasonable safeguards to protect your data. However, no internet transmission is 100% secure.\n\n## 7. Your Rights\n\nYou may:\n\n- Access and correct your data\n- Withdraw consent\n- Request deletion\n\nContact team@didisnow.com to exercise these rights.\n\n## 8. Third-Party Links\n\nOur Platform may link to external sites. We are not responsible for their privacy practices or content.\n\n## 9. Children''s Privacy\n\nOur services are not directed to children under 18, and we do not knowingly collect data from children.\n\n## 10. Changes to This Policy\n\nWe may update this Policy from time to time. Updates will be posted here with a revised date. Continued use constitutes acceptance.\n\n## 11. Grievance Officer\n\n**Grievance Officer**\nDidi Now Private Limited\nPrestige High Fields, Hyderabad – 500032\nEmail: team@didisnow.com\nPhone: +91 8008180018\n\n## 12. Contact Us\n\n- Email: team@didisnow.com\n- Phone: +91 8008180018\n- Website: https://user.didisnow.com\n\nBy using Didi Now, you confirm you have read and agree to this Privacy Policy.'
)
ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;

-- Add timestamp for tracking when policy was updated
INSERT INTO public.ops_settings (key, value)
VALUES ('privacy_policy_updated_at', now()::text)
ON CONFLICT (key) DO UPDATE SET value = now()::text;